import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"技术栈总览","description":"","frontmatter":{},"headers":[],"relativePath":"overview/index.md","filePath":"overview/index.md","lastUpdated":null}'),i={name:"overview/index.md"};function n(s,t,l,o,p,c){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="技术栈总览" tabindex="-1">技术栈总览 <a class="header-anchor" href="#技术栈总览" aria-label="Permalink to &quot;技术栈总览&quot;">​</a></h1><p>企业 Java 开发 Spring Cloud 微服务项目，完整技术栈一般不是一个框架能解决的，而是一整套组件组合。</p><p>但要注意：<strong>不是所有项目都必须全部使用</strong>。应该根据项目规模、业务复杂度、团队能力逐步选择。</p><h2 id="核心组合速查" tabindex="-1">核心组合速查 <a class="header-anchor" href="#核心组合速查" aria-label="Permalink to &quot;核心组合速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>类别</th><th>主要作用</th></tr></thead><tbody><tr><td>Spring Boot</td><td>基础框架</td><td>单个微服务的基础开发框架，负责应用启动、自动配置和业务接口开发。</td></tr><tr><td>Spring Cloud</td><td>微服务治理</td><td>负责服务发现、服务调用、网关、负载均衡等微服务能力。</td></tr><tr><td>Spring Cloud Alibaba</td><td>微服务扩展</td><td>国内常用的 Spring Cloud 扩展，整合 Nacos、Sentinel、RocketMQ、Seata 等组件。</td></tr><tr><td>Nacos</td><td>注册配置</td><td>注册中心和配置中心，负责服务注册发现以及统一配置管理。</td></tr><tr><td>Gateway</td><td>网关</td><td>微服务统一入口，负责路由转发、鉴权、限流、跨域和灰度流量控制。</td></tr><tr><td>OpenFeign</td><td>服务调用</td><td>声明式 HTTP 客户端，用接口方式完成微服务之间的远程调用。</td></tr><tr><td>Sentinel / Resilience4j</td><td>稳定性治理</td><td>负责限流、熔断、降级、超时和重试控制。</td></tr><tr><td>MySQL</td><td>数据库</td><td>关系型数据库，负责保存核心业务数据和事务数据。</td></tr><tr><td>Redis</td><td>缓存</td><td>内存缓存数据库，负责缓存、分布式锁、验证码、Token 和热点数据加速。</td></tr><tr><td>Elasticsearch</td><td>搜索分析</td><td>分布式搜索和分析引擎，负责全文搜索、复杂检索、聚合分析和日志检索。</td></tr><tr><td>RocketMQ / Kafka / RabbitMQ</td><td>消息队列</td><td>负责异步解耦、削峰填谷、事件驱动和最终一致性。</td></tr><tr><td>Seata</td><td>分布式事务</td><td>处理跨服务、跨数据库的事务一致性问题。</td></tr><tr><td>Spring Security / OAuth2 / JWT</td><td>认证授权</td><td>负责登录认证、接口鉴权、Token 校验和权限控制。</td></tr><tr><td>XXL-Job</td><td>任务调度</td><td>分布式任务调度平台，负责任务定时执行、分片执行和任务管理。</td></tr><tr><td>MinIO / OSS</td><td>文件存储</td><td>对象存储服务，负责图片、附件、合同、Excel、PDF 等文件存储。</td></tr><tr><td>Prometheus</td><td>指标监控</td><td>指标采集和监控系统，负责采集服务、接口、JVM、容器等运行指标。</td></tr><tr><td>Grafana</td><td>监控看板</td><td>监控可视化平台，负责展示 Prometheus 等数据源的监控看板。</td></tr><tr><td>SkyWalking / OpenTelemetry</td><td>链路追踪</td><td>负责追踪微服务调用链和定位性能问题。</td></tr><tr><td>ELK / Loki</td><td>日志平台</td><td>日志采集、存储和检索系统，负责集中查看应用日志和异常日志。</td></tr><tr><td>Docker</td><td>容器化</td><td>把应用和运行环境打包成标准镜像，方便部署和迁移。</td></tr><tr><td>Kubernetes</td><td>容器编排</td><td>负责服务部署、扩缩容、滚动发布和故障恢复。</td></tr><tr><td>Jenkins / GitLab CI</td><td>CI/CD</td><td>持续集成和持续部署工具，负责编译、测试、构建镜像和自动发布。</td></tr></tbody></table><h2 id="怎么读这个文档库" tabindex="-1">怎么读这个文档库 <a class="header-anchor" href="#怎么读这个文档库" aria-label="Permalink to &quot;怎么读这个文档库&quot;">​</a></h2><p>本文档库按技术分层组织，每一层对应一个栏目：</p><ul><li><a href="./architecture">整体架构</a>：一个典型企业 Spring Cloud 项目长什么样。</li><li><a href="./selection">按规模选型</a>：小型、中型、大型项目分别该用哪些组件。</li><li><a href="./roadmap">学习路线</a>：从零开始学习企业 Java 的推荐顺序，以及重点记忆版。</li></ul><p>各组件的详细说明分布在以下栏目。其中<strong>语言基础</strong>部分（Java 基础、Spring 核心、工程实践）不在原始技术栈清单中，是为构成&quot;全技术&quot;知识库而补充的底层内容：</p><ul><li><a href="/my-docs/java-core/">Java 基础</a>：语言核心、JVM 原理与调优、并发编程。</li><li><a href="/my-docs/spring-core/">Spring 核心</a>：IoC/DI、AOP、事务原理。</li><li><a href="/my-docs/framework/">核心框架</a>：Spring Boot、Spring Cloud、Nacos、Gateway、OpenFeign、Sentinel。</li><li><a href="/my-docs/storage/">数据存储</a>：MySQL、MyBatis-Plus、Redis、Elasticsearch、分库分表、分布式 ID、数据同步。</li><li><a href="/my-docs/messaging/">消息与事务</a>：RocketMQ、Kafka、Seata。</li><li><a href="/my-docs/security/">安全与认证</a>：Spring Security、OAuth2、JWT、Sa-Token、密钥管理。</li><li><a href="/my-docs/practice/">工程实践</a>：Maven 构建、设计模式、SQL 优化、API 设计规范。</li><li><a href="/my-docs/engineering/">工程能力</a>：文件存储、定时任务、接口文档、测试、代码质量、开发辅助。</li><li><a href="/my-docs/observability/">可观测性</a>：Prometheus、Grafana、SkyWalking、日志平台。</li><li><a href="/my-docs/deploy/">部署运维</a>：Docker、Kubernetes、CI/CD、服务网格、数据分析、AI 能力。</li></ul><h2 id="最终建议" tabindex="-1">最终建议 <a class="header-anchor" href="#最终建议" aria-label="Permalink to &quot;最终建议&quot;">​</a></h2><p>不要为了&quot;完整&quot;而一次性引入所有组件。实际项目推荐原则：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先满足业务</span></span>
<span class="line"><span>再解决性能</span></span>
<span class="line"><span>再解决稳定性</span></span>
<span class="line"><span>再解决可观测性</span></span>
<span class="line"><span>再解决自动化交付</span></span>
<span class="line"><span>最后再考虑高级治理</span></span></code></pre></div>`,13)])])}const g=d(i,[["render",n]]);export{u as __pageData,g as default};
